/**
 * SPEC-021: card "Coste de IA" de Ajustes (componente aislado; frontera de
 * mocking: window.api.db.getAiCostSettings/setAiCostSettings).
 * Generated by QA Dev agent.
 */
import { render, screen, waitFor, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { Toaster } from '@/components/ui/sonner'
import { AiCostCard } from '@/components/settings/AiCostCard'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

function renderCard(): RenderResult {
  return render(
    <>
      <AiCostCard />
      <Toaster />
    </>
  )
}

async function findLimitInput(): Promise<HTMLElement> {
  const input = await screen.findByLabelText('Límite por entrevista (USD)')
  await waitFor(() => expect(input).toBeEnabled())
  return input
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.setAiCostSettings).mockResolvedValue({
    ok: true,
    data: { limitUsd: 2.5 }
  })
})

describe('AiCostCard', () => {
  // SPEC-021 · AC-09
  it('renders the "Coste de IA" card preloading the persisted limit and saves it with the "Ajustes guardados" toast', async () => {
    vi.mocked(mockApi.api.db.getAiCostSettings).mockResolvedValue({
      ok: true,
      data: { limitUsd: 1.5 }
    })
    const user = userEvent.setup()
    renderCard()

    // Card con título, descripción y el disclaimer permanente de la tarifa
    expect(await screen.findByTestId('ai-cost-settings-card')).toBeInTheDocument()
    expect(screen.getByText('Coste de IA')).toBeInTheDocument()
    expect(
      screen.getByText(
        'Límite de gasto estimado por entrevista para el asistente en vivo. El guión y la nota no se bloquean.'
      )
    ).toBeInTheDocument()
    expect(
      screen.getByText(
        'Coste estimado según la tarifa del modelo configurado en la app; orientativo, no factura real.'
      )
    ).toBeInTheDocument()
    // El input precarga el límite persistido (placeholder "Sin límite")
    const input = await findLimitInput()
    expect(input).toHaveValue('1.5')
    expect(input).toHaveAttribute('placeholder', 'Sin límite')

    await user.clear(input)
    await user.type(input, '2.50')
    await user.click(screen.getByRole('button', { name: 'Guardar' }))

    expect(vi.mocked(mockApi.api.db.setAiCostSettings)).toHaveBeenCalledWith({ limitUsd: 2.5 })
    expect((await screen.findAllByText('Ajustes guardados')).length).toBeGreaterThanOrEqual(1)
  })

  // SPEC-021 · AC-09 (refuerzo: vacío = sin límite; coma decimal es-ES normalizada)
  it('saves an empty field as no limit and normalizes the Spanish decimal comma', async () => {
    const user = userEvent.setup()
    renderCard()
    const input = await findLimitInput()

    // Vacío → { limitUsd: null }
    await user.click(screen.getByRole('button', { name: 'Guardar' }))
    expect(vi.mocked(mockApi.api.db.setAiCostSettings)).toHaveBeenCalledWith({ limitUsd: null })

    // "0,50" con coma (teclado es-ES) → 0.5
    await user.type(input, '0,50')
    await user.click(screen.getByRole('button', { name: 'Guardar' }))
    expect(vi.mocked(mockApi.api.db.setAiCostSettings)).toHaveBeenLastCalledWith({
      limitUsd: 0.5
    })
  })

  // SPEC-021 · AC-10
  it('shows the exact inline error and persists nothing for non-numeric or negative values', async () => {
    const user = userEvent.setup()
    renderCard()
    const input = await findLimitInput()

    await user.type(input, '-1')
    await user.click(screen.getByRole('button', { name: 'Guardar' }))
    expect(
      await screen.findByText('Introduce un importe positivo o deja el campo vacío')
    ).toBeInTheDocument()

    await user.clear(input)
    await user.type(input, 'gratis')
    await user.click(screen.getByRole('button', { name: 'Guardar' }))
    expect(
      await screen.findByText('Introduce un importe positivo o deja el campo vacío')
    ).toBeInTheDocument()

    expect(vi.mocked(mockApi.api.db.setAiCostSettings)).not.toHaveBeenCalled()
  })
})
